  // Look for Apify results in various possible locations
  const raw = item.json.output || 
               item.json.text || 
               item.json.results || 
               JSON.stringify(item.json);

  try {
    let parsed = null;

    // Try to parse as JSON
    if (typeof raw === 'string') {
      parsed = JSON.parse(raw);
    } else if (typeof raw === 'object') {
      parsed = raw;
    }

    // Handle Apify's specific output structure
    if (parsed) {
      // Case 1: Direct prospects array
      if (parsed.prospects && Array.isArray(parsed.prospects)) {
        prospects = parsed.prospects;
      }
      // Case 2: Apify organic results
      else if (parsed.organicResults && Array.isArray(parsed.organicResults)) {
        prospects = parsed.organicResults.map(result => ({
