          phone: '',
          company_size: '',
          decision_maker: '',
          decision_maker_title: '',
          linkedin: result.url?.includes('linkedin.com') ? result.url : '',
          industry: 'Marketing Agency',
          score: 50,
          priority: 'Warm',
          score_reason: 'Found via Google search'
        }));
      }
      // Case 3: Individual company object
      else if (parsed.company || parsed.website) {
        prospects = [parsed];
      }
      // Case 4: Search results from Apify's default format
