// Force extract JSON from agent's text output
const items = $input.all();
const extractedProspects = [];

for (const item of items) {
  const agentOutput = item.json.output || item.json.text || JSON.stringify(item.json);

  // Try multiple JSON extraction patterns
  const patterns = [
    /\[\s*\{\s*"company"[\s\S]*?\}\s*\]/,  // Array of prospects
    /\{\s*"prospects"\s*:\s*\[[\s\S]*?\]\s*\}/,  // prospects object
    /\{\s*"company"[\s\S]*?"score"[\s\S]*?\}/,  // Single prospect
    /```json\s*([\s\S]*?)\s*```/,  // Markdown code block
    /(\{\s*"company"[\s\S]*?\})/  // Any JSON object with company
  ];

  let found = false;

  for (const pattern of patterns) {
    const match = agentOutput.match(pattern);
    if (match) {
      try {
        let parsed = match[1] || match[0];
        let jsonData = JSON.parse(parsed);

        // Handle different structures
        let prospects = [];
        if (jsonData.prospects && Array.isArray(jsonData.prospects)) {
          prospects = jsonData.prospects;
        } else if (Array.isArray(jsonData)) {
          prospects = jsonData;
        } else if (jsonData.company) {
          prospects = [jsonData];
        }

        // Clean and validate each prospect
        for (const p of prospects) {
          extractedProspects.push({
            json: {
              company: p.company || p.name || 'Unknown',
              industry: p.industry || 'Marketing Agency',
              location: p.location || p.country || 'East Africa',
              website: p.website || p.url || p.link || '',
              email: p.email || p.contact_email || '',
              phone: p.phone || '',
              company_size: p.company_size || p.size || '',
              description: p.description || p.about || '',
              decision_maker: p.decision_maker || p.contact_name || p.ceo || p.founder || '',
              decision_maker_title: p.decision_maker_title || p.title || p.position || '',
              linkedin: (p.linkedin || p.linkedin_url || '').includes('linkedin.com/in/') ? (p.linkedin || p.linkedin_url) : '',
              score: p.score || 50,
              priority: p.priority || 'Cold',
              score_reason: p.score_reason || 'Extracted from agent output',
              source: 'Research Agent',
              date_added: new Date().toISOString().split('T')[0]
            }
          });
        }
        found = true;
        break;
      } catch(e) {
        console.log('Parse attempt failed:', e.message);
      }
    }
  }

  // If still no data found, create a fallback from visible data in the text
  if (!found && extractedProspects.length === 0) {
    // Try to extract company name from agent's text
    const companyMatch = agentOutput.match(/company["\s:]+([A-Z][a-zA-Z\s]+?)(?=["\s,]|$)/i);
    const emailMatch = agentOutput.match(/[\w\.-]+@[\w\.-]+\.\w+/);
    const linkedinMatch = agentOutput.match(/linkedin\.com\/in\/[\w-]+/);

    if (companyMatch || emailMatch) {
      extractedProspects.push({
        json: {
          company: companyMatch ? companyMatch[1].trim() : 'Unknown',
          industry: 'Marketing Agency',
          location: 'East Africa',
          website: '',
          email: emailMatch ? emailMatch[0] : '',
          phone: '',
          company_size: '',
          description: '',
          decision_maker: '',
          decision_maker_title: '',
          linkedin: linkedinMatch ? `https://${linkedinMatch[0]}` : '',
          score: 30,
          priority: 'Cold',
          score_reason: 'Extracted from text pattern matching',
          source: 'Agent Text Parsing',
          date_added: new Date().toISOString().split('T')[0]
        }
      });
    }
  }
}

// Return what we found
if (extractedProspects.length === 0) {
  return [{
    json: {
      error: 'No prospects extracted',
      raw_agent_output: items[0]?.json?.output || items[0]?.json?.text || 'No output found',
      timestamp: new Date().toISOString()
    }
  }];
}

return extractedProspects;
